def multiplication_table(n):
    """Return a list of 'n x i = result' strings for i from 1 to 10."""
    result = []
    for i in range(1, 11):
        result.append(f"{n} x {i} = {n * i}")
    return result


def fizzbuzz(n):
    """Return a FizzBuzz list for numbers 1 through n."""
    result = []
    for i in range(1, n + 1):
        if i % 15 == 0:
            result.append("FizzBuzz")
        elif i % 3 == 0:
            result.append("Fizz")
        elif i % 5 == 0:
            result.append("Buzz")
        else:
            result.append(str(i))
    return result


def sum_range(start, end):
    """Return the sum of integers from start to end (inclusive)."""
    return sum(range(start, end + 1))


def count_digits(n):
    """Return the number of digits in the absolute value of n."""
    return len(str(abs(n)))
